-- 🔑 CONFIG
local KEY = "BLOXYHAIANH-618900"
local GET_KEY_LINK = "https://direct-link.net/4841861/Ax49QYwW05Em"

-- 📦 FUNCTION HIỆN UI + CHECK
local function ShowKeyUI()
    local done = false

    -- UI
    local gui = Instance.new("ScreenGui", game.CoreGui)

    local frame = Instance.new("Frame", gui)
    frame.Size = UDim2.new(0, 300, 0, 160)
    frame.Position = UDim2.new(0.5, -150, 0.5, -80)
    frame.BackgroundColor3 = Color3.fromRGB(25,25,25)

    local box = Instance.new("TextBox", frame)
    box.Size = UDim2.new(0, 260, 0, 40)
    box.Position = UDim2.new(0, 20, 0, 20)
    box.PlaceholderText = "Nhập key..."
    box.Text = ""

    local btn = Instance.new("TextButton", frame)
    btn.Size = UDim2.new(0, 260, 0, 40)
    btn.Position = UDim2.new(0, 20, 0, 70)
    btn.Text = "Xác nhận"

    local copy = Instance.new("TextButton", frame)
    copy.Size = UDim2.new(0, 260, 0, 30)
    copy.Position = UDim2.new(0, 20, 0, 115)
    copy.Text = "📋 Copy link lấy key"

    -- copy link
    copy.MouseButton1Click:Connect(function()
        setclipboard(GET_KEY_LINK)
    end)

    -- check key
    btn.MouseButton1Click:Connect(function()
        if box.Text == KEY then
            done = true
            gui:Destroy()
        else
            box.Text = ""
            box.PlaceholderText = "Sai key!"
        end
    end)

    -- đợi nhập đúng
    repeat task.wait() until done

    return true
end

local b=''
local function d(s)
    local b='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    s=string.gsub(s,'[^'..b..'=]','')
    return (s:gsub('.',function(x)
        if (x=='=') then return '' end
        local r,f='',(b:find(x)-1)
        for i=6,1,-1 do
            r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0')
        end
        return r;
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?',function(x)
        if (#x~=8) then return '' end
        local c=0
        for i=1,8 do
            c=c+(x:sub(i,i)=='1' and 2^(8-i) or 0)
        end
        return string.char(c)
    end))
end

loadstring(d(b))()
